function isPointInTriangle(px, py, x1, y1, x2, y2, x3, y3) {
  const denominator = (y2 - y3) * (x1 - x3) + (x3 - x2) * (y1 - y3);
  const a = ((y2 - y3) * (px - x3) + (x3 - x2) * (py - y3)) / denominator;
  const b = ((y3 - y1) * (px - x3) + (x1 - x3) * (py - y3)) / denominator;
  const c = 1 - a - b;

  return a >= 0 && a <= 1 && b >= 0 && b <= 1 && c >= 0 && c <= 1;
}

function advanceMonth(value) {
  var d = new Date(value);
  var month = d.getMonth() + 1;
  var year = d.getFullYear() + (month > 11 ? 1 : 0);
  month = month % 12;
  var lastDay = new Date(year, month + 1, 0).getDate();
  var day = Math.min(d.getDate(), lastDay);
  var mm = String(month + 1).padStart(2, "0");
  var dd = String(day).padStart(2, "0");
  return `${mm}/${dd}/${year}`;
}

function convertDocKbdToKbdForMarkdown(body: string) {
  return body
    .replace(DOC_KBD_SELF_CLOSING_DQUOT_RE, (_m, label: string) => {
      return `<kbd>${escapeKbdInnerText(label)}</kbd>`;
    })
    .replace(DOC_KBD_SELF_CLOSING_SQUOT_RE, (_m, label: string) => {
      return `<kbd>${escapeKbdInnerText(label)}</kbd>`;
    });
}

(item) => {
	// eslint-disable-next-line svelte/prefer-svelte-reactivity
	const referenceDate = new Date("2024-06-30");
	let daysToSubtract = 90;
	if (timeRange === "30d") {
		daysToSubtract = 30;
	} else if (timeRange === "7d") {
		daysToSubtract = 7;
	}

	referenceDate.setDate(referenceDate.getDate() - daysToSubtract);
	return item.date >= referenceDate;
}

export function toggle<T>(
	item: T,
	array: T[],
	compare: (itemA: T, itemB: T) => boolean = deepEqual
): T[] {
	const itemIdx = array.findIndex((innerItem) => compare(innerItem, item));
	if (itemIdx !== -1) {
		array.splice(itemIdx, 1);
	} else {
		array.push(item);
	}

	return array;
}

function getDocumentation(symbol: Symbol): JSDoc {
	const jsDoc = symbol
		.getDeclarations()
		.filter((decl) => Node.isJSDocable(decl))
		.flatMap((decl) => decl.getJsDocs())
		.at(0);

	if (!jsDoc) return { description: null, tags: [] };

	return {
		description: jsDoc.getDescription().trim(),
		tags: jsDoc.getTags().map((tag) => ({ name: tag.getTagName(), value: tag.getCommentText() ?? null })),
	};
}

function sort_static(a, b) {
	if (a === b) return 0;

	for (let i = 0; true; i += 1) {
		const char_a = a[i];
		const char_b = b[i];

		if (char_a !== char_b) {
			if (char_a === undefined) return +1;
			if (char_b === undefined) return -1;
			return char_a < char_b ? -1 : +1;
		}
	}
}

function normalizeDriveLetter(path: string): string {
    if (path.charCodeAt(1) !== /*:*/ 58) {
        return path;
    }

    const driveLetter = path.charCodeAt(0);
    if (driveLetter >= /*A*/ 65 && driveLetter <= /*Z*/ 90) {
        return String.fromCharCode(driveLetter + 32) + path.slice(1);
    }

    return path;
}

function getTriggerCharacter(content: string) {
    const chars = [
        getLastIndexOf('#'),
        getLastIndexOf('/'),
        getLastIndexOf(':'),
        getLastIndexOf('@')
    ];
    return chars.sort((c1, c2) => c2.idx - c1.idx)[0].char;

    function getLastIndexOf(char: '#' | '/' | ':' | '@') {
        return { char, idx: content.lastIndexOf(char) };
    }
}

export function isElseBlockWithElseIf(node: SvelteNode | null | undefined) {
    return (
        !!node &&
        node.type === 'ElseBlock' &&
        'children' in node &&
        Array.isArray(node.children) &&
        node.children.length === 1 &&
        node.children[0].type === 'IfBlock'
    );
}

export function modifyLines(
    text: string,
    replacementFn: (line: string, lineIdx: number) => string
): string {
    let idx = 0;
    return text
        .split('\r\n')
        .map((l1) =>
            l1
                .split('\n')
                .map((line) => replacementFn(line, idx++))
                .join('\n')
        )
        .join('\r\n');
}

getNodesThatRecursivelyReferenceType(name: string) {
    let types: string[] = [name];
    const nodes: Set<TypeOrInterface> = new Set();
    while (types.length !== 0) {
        const newTypes = flatten(
            types.map((type) => this.getNodesThatReferenceType(type))
        ).filter((t) => !nodes.has(t));
        newTypes.forEach((t) => nodes.add(t));
        types = newTypes.map((t) => t.name.text);
    }
    return [...nodes.values()];
}

checkIfElementIsScriptTag(node: Node, parent: Node) {
    if (parent !== this.htmlxAst && node.name === 'script') {
        this.topLevelScripts = this.topLevelScripts.filter(
            (tag) => tag.start !== node.start || tag.end !== node.end
        );
    }
}

function _distance(str1, str2) {
	if (str1 === null && str2 === null) {
		throw 'Trying to compare two null values';
	}
	if (str1 === null || str2 === null) return 0;
	str1 = String(str1);
	str2 = String(str2);

	const distance = levenshtein(str1, str2);
	return 1 - distance / Math.max(str1.length, str2.length);
}

export function get_parent(path, at) {
	let node = path.at(at);
	// @ts-expect-error
	if (node.type === 'TSNonNullExpression' || node.type === 'TSAsExpression') {
		return /** @type {T} */ (path.at(at < 0 ? at - 1 : at + 1));
	}
	return /** @type {T} */ (node);
}

function is_active(key, e) {
	switch (key) {
		case 'shift':
		case 'control':
		case 'alt':
		case 'meta':
			return e.getModifierState(key.charAt(0).toUpperCase() + key.slice(1));
		default:
			return key === e.code.replace(/^Key/, '').toLowerCase() || key === e.key.toLowerCase();
	}
}

